package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Create a new CSVFormat instance with nullString == null using reflection to bypass immutability
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to get the private final field nullString
        Field field = CSVFormat.class.getDeclaredField("nullString");
        field.setAccessible(true);

        // Remove final modifier from the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        // Set nullString to null
        field.set(format, null);

        boolean result = format.isNullStringSet();

        assertFalse(result);
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Create a CSVFormat instance with a non-null nullString
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");

        // Use reflection to confirm the private field nullString is set
        Field field = CSVFormat.class.getDeclaredField("nullString");
        field.setAccessible(true);
        Object nullStringValue = field.get(format);
        assertEquals("NULL", nullStringValue);

        boolean result = format.isNullStringSet();

        assertTrue(result);
    }

}
